const { Storage } = require('@google-cloud/storage');
const storage = new Storage();

exports.serveFile = async (req, res) => {
  // Set CORS headers for preflight requests
  if (req.method === 'OPTIONS') {
    res.set('Access-Control-Allow-Origin', '*');
    res.set('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
    res.set('Access-Control-Allow-Headers', 'Content-Type, Authorization');
    res.status(204).send('');
    return;
  }

  // Set CORS headers for the main request
  res.set('Access-Control-Allow-Origin', '*');
  res.set('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  res.set('Access-Control-Allow-Headers', 'Content-Type, Authorization');

  try {
    const bucketName = req.query.bucket;
    const filePath = req.query.path;

    // Validate inputs
    if (!bucketName || !filePath) {
      return res.status(400).send('Bucket and path parameters are required');
    }

    // Validate bucket name format
    if (!/^[a-z0-9][a-z0-9._-]*[a-z0-9]$/.test(bucketName)) {
      return res.status(400).send('Invalid bucket name format');
    }

    // Validate file path - prevent directory traversal
    if (filePath.includes('..') || filePath.startsWith('/')) {
      return res.status(400).send('Invalid file path');
    }

    // Sanitize file path
    const sanitizedPath = filePath.replace(/^\/+|\/+$/g, '');

    // Get bucket and file reference
    const bucket = storage.bucket(bucketName);
    const file = bucket.file(sanitizedPath);

    // Check if file exists
    const [exists] = await file.exists();
    if (!exists) {
      return res.status(404).send('File not found');
    }

    // Set appropriate content type
    const contentType = getContentType(sanitizedPath);
    if (contentType) {
      res.set('Content-Type', contentType);
    }

    // Stream file to client
    const fileStream = file.createReadStream();
    fileStream.on('error', (err) => {
      console.error('Error reading file:', err);
      res.status(500).send('Error reading file');
    });
    
    fileStream.pipe(res);
    
  } catch (error) {
    console.error('Error serving file:', error);
    res.status(500).send('Internal server error');
  }
};

function getContentType(filePath) {
  const ext = filePath.split('.').pop().toLowerCase();
  const mimeTypes = {
    'jpg': 'image/jpeg',
    'jpeg': 'image/jpeg',
    'png': 'image/png',
    'gif': 'image/gif',
    'bmp': 'image/bmp',
    'svg': 'image/svg+xml',
    'webp': 'image/webp',
    'ico': 'image/x-icon',
    'pdf': 'application/pdf',
    'txt': 'text/plain',
    'html': 'text/html',
    'css': 'text/css',
    'js': 'application/javascript',
    'json': 'application/json',
    'xml': 'application/xml',
    'zip': 'application/zip',
    'mp4': 'video/mp4',
    'webm': 'video/webm',
    'ogg': 'video/ogg',
    'mp3': 'audio/mpeg',
    'wav': 'audio/wav',
    'ogg': 'audio/ogg'
  };
  
  return mimeTypes[ext] || 'application/octet-stream';
}